from collections import deque

class Solution:
    def minDepth(self, root):
        if root is None:
            return 0
        q = deque([(root, 1)])
        while q:
            node, d = q.popleft()
            if node.left is None and node.right is None:
                return d
            if node.left:
                q.append((node.left, d + 1))
            if node.right:
                q.append((node.right, d + 1))
        return 0

